mapper.update:
UPDATE room_members
SET status = 'LEFT', left_at = #{leftAt}
WHERE room_id = #{roomId} AND user_id = #{userId} AND status = 'ACTIVE'

UPDATE room_members
SET status_message = #{statusMessage}
WHERE room_id = #{roomId} AND user_id = #{userId} AND status = 'ACTIVE'

UPDATE room_members
SET is_favorite = #{isFavorite}
WHERE room_id = #{roomId} AND user_id = #{userId} AND status = 'ACTIVE'

UPDATE room_members
SET status = 'ACTIVE', left_at = NULL, joined_at = #{joinedAt}
WHERE room_id = #{roomId} AND user_id = #{userId} AND status = 'LEFT'
